import{_ as d,o as r,c as a,a2 as p}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"巴菲特合伙有限公司","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1966年/年中信.md","filePath":"01_letters/1966年/年中信.md"}'),e={name:"01_letters/1966年/年中信.md"};function o(l,t,h,n,i,s){return r(),a("div",null,[...t[0]||(t[0]=[p('<h1 id="巴菲特合伙有限公司" tabindex="-1">巴菲特合伙有限公司 <a class="header-anchor" href="#巴菲特合伙有限公司" aria-label="Permalink to &quot;巴菲特合伙有限公司&quot;">​</a></h1><h2 id="_1966年7月12日-上半年业绩报告" tabindex="-1">1966年7月12日 上半年业绩报告 <a class="header-anchor" href="#_1966年7月12日-上半年业绩报告" aria-label="Permalink to &quot;1966年7月12日 上半年业绩报告&quot;">​</a></h2><p>电话：042-4110</p><h3 id="上半年业绩表现" tabindex="-1">上半年业绩表现 <a class="header-anchor" href="#上半年业绩表现" aria-label="Permalink to &quot;上半年业绩表现&quot;">​</a></h3><p>1966年上半年，道琼斯工业平均指数（以下简称“道指”）从969.26点跌至870.10点。若在此期间持有道指成分股，可获得约14.70点的股息收益，整体亏损幅度收窄至约8.7%。</p><p>我的目标与期望（绝非预测！）是，长期来看，我们的年化收益能跑赢道指10个百分点。上半年我们的表现远超预期，整体收益约8.2%。这样的成绩显然是异常的。我此前曾夸赞合伙人们心态豁达，能坦然接受这类超出预期的正向收益。我们的投资生意注定如此，未来岁月里，那些希望考验自己承受负向收益能力的合伙人，大概率不会失望。</p><p>以下是道指年度表现、合伙公司分配给普通合伙人前的业绩，以及有限合伙人收益的年度汇总：</p><table tabindex="0"><thead><tr><th>年份</th><th>道指整体收益(1)</th><th>合伙公司业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964</td><td>18.7%</td><td>27.8%</td><td>22.3%</td></tr><tr><td>1965</td><td>14.2%</td><td>47.2%</td><td>36.9%</td></tr><tr><td>1966年上半年</td><td>-8.7%</td><td>8.2%</td><td>7.7%</td></tr><tr><td>累计收益</td><td>141.1%</td><td>1028.7%</td><td>641.5%</td></tr><tr><td>年化复合收益率</td><td>9.7%</td><td>29.0%</td><td>23.5%</td></tr></tbody></table><ol><li><p>基于道指年度市值变动，加上持有道指成分股当年可获得的股息计算，表格包含合伙公司运营的所有完整年度数据。</p></li><li><p>1957-1961年数据为所有前身有限合伙企业全年运营、扣除所有费用后，向合伙人分配及普通合伙人分成前的合并业绩。</p></li><li><p>1957-1961年数据基于上一列合伙公司业绩，按照现行合伙协议扣除普通合伙人分成后、有限合伙人月度赎回前的收益计算。</p></li></ol><p>即便是大力士参孙，也偶有受挫之时。若你在1966年1月1日将10万美元等额投资于以下8家巨头企业：</p><p>a. 全球最大汽车公司——通用汽车</p><p>b. 全球最大石油公司——新泽西标准石油</p><p>c. 全球最大零售公司——西尔斯罗巴克</p><p>d. 全球最大化工公司——杜邦</p><p>e. 全球最大钢铁公司——美国钢铁</p><p>f. 全球最大股份制保险公司——安泰保险</p><p>g. 全球最大公共事业公司——美国电话电报公司</p><p>h. 全球最大银行——美国银行</p><p>截至6月30日，你的投资组合（含股息）市值仅为83370美元，亏损16.6%。这8家巨头1月1日总市值超1000亿美元，半年后股价悉数下跌。</p><h3 id="投资公司对比" tabindex="-1">投资公司对比 <a class="header-anchor" href="#投资公司对比" aria-label="Permalink to &quot;投资公司对比&quot;">​</a></h3><p>下页为我们定期更新的对比数据，对象是两家规模最大、通常95%-10%资金投资于普通股的开放式共同基金，以及两家规模最大的多元化封闭式投资公司。</p><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资信托(1)</th><th>投资者股票基金(1)</th><th>雷曼基金(2)</th><th>三大陆基金(2)</th><th>道指</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.7%</td><td>18.3%</td><td>20.6%</td><td>30.5%</td></tr><tr><td>1964</td><td>15.9%</td><td>14.3%</td><td>13.6%</td><td>12.6%</td><td>18.7%</td><td>22.3%</td></tr><tr><td>1965</td><td>10.2%</td><td>9.8%</td><td>19.0%</td><td>10.7%</td><td>14.2%</td><td>36.9%</td></tr><tr><td>1966年上半年</td><td>-7.9%</td><td>-7.9%</td><td>-1.0%</td><td>-5.2%</td><td>-8.7%</td><td>7.7%</td></tr><tr><td>累计收益</td><td>118.1%</td><td>106.3%</td><td>142.8%</td><td>126.9%</td><td>141.1%</td><td>641.5%</td></tr><tr><td>年化复合收益率</td><td>8.6%</td><td>7.9%</td><td>9.8%</td><td>9.0%</td><td>9.7%</td><td>23.5%</td></tr></tbody></table><ol><li><p>基于资产净值变动，加上当年向在册持有人分配的收益计算。</p></li><li><p>1957-1965年数据来自1966年《穆迪银行与金融手册》，1966年上半年为估算值。</p></li></ol><p>机构投资的支持者常标榜其“稳健性”。若将“稳健”定义为<strong>收益与市场平均水平偏差极小</strong>，我认为这个定位是准确的——广泛配置高评级证券，必然会带来这样的结果。长期来看，“市场平均水平”往往是不错的收益，普通投资者选择这类投资工具并无不妥。</p><p>但我认为，<strong>真正的稳健</strong>应是<strong>价值临时或永久缩水幅度远低于市场整体</strong>。从这四家管理规模超50亿美元的大型基金业绩来看，它们并未做到这一点。具体而言，道指在1957、1960、1962年及1966年上半年下跌，三个完整年度累计跌幅20.6%；四家基金同期累计跌幅分别为9.7%、20.9%、22.3%、24.6%。计入1966年上半年数据后，道指累计跌27.5%，基金则分别跌14.4%、23.1%、27.1%、30.6%。这类基金（我认为其业绩代表了普通股机构投资的普遍水平）符合第一种“稳健”定义，却不符合第二种。</p><p>若投资者能清晰区分这两种“稳健”，投资认知会更上一层。第一种更适合被称作**“随大流”<strong>——市场普涨时我们跟着赚，幅度差不多；市场普跌时我们跟着亏，幅度也差不多。这绝非</strong>“市场涨时赚得相当，市场跌时亏得更少”**。极少有投资策略能实现后者——我们从不承诺，但会一直努力。我始终认为，我们的目标应比赫尔曼·希克曼更崇高。当年耶鲁大学橄榄球队连年惨败，希克曼曾说：“我的工作就是让校友们不满，但不至于造反。”</p><h3 id="霍奇希尔德·科恩公司" tabindex="-1">霍奇希尔德·科恩公司 <a class="header-anchor" href="#霍奇希尔德·科恩公司" aria-label="Permalink to &quot;霍奇希尔德·科恩公司&quot;">​</a></h3><p>上半年，我们与两位持股10%的合伙人，通过协商收购了巴尔的摩私营百货公司霍奇希尔德·科恩公司（以下简称HK）的全部股份。这是合伙公司历史上首次通过协商收购整家企业，此前我们仅协商收购过特定大额流通证券。但投资原则并未改变：我们会从定量和定性维度评估企业，对比绝对价格与其他投资机会的相对价值，HK在各方面都表现优异。</p><p>我们拥有顶尖的运营团队（无论人品还是业务能力）。尽管早年我在奥马哈彭尼商店时薪75美分的打工经历，让我对《最低工资法》颇有研究，但我们仍会让原有团队按既往模式运营。即便收购价格更低，若管理层平庸，我们也不会出手。</p><p>收购一家数千名员工的企业，难免引发公众关注，但请不要因新闻热度，高估其对合伙公司的财务重要性。我们总投资超5000万美元，主要投向流通证券，HK净投资仅占约10%。我们有一笔三倍于此的流通证券投资，永远不会被公众知晓。这并非说HK不重要——10%的持仓无疑关键，但它对整体业务的影响，远没有外界想象中那么大。我依旧偏爱**“冰山式”**投资披露策略。</p><p>我计划年末按<strong>收购成本+收购后留存收益</strong>评估HK价值，未来除非其相对其他百货公司的地位或客观估值标准发生明显变化，否则将沿用此政策。我们之所以收购，正是因为价格极具吸引力，因此按成本估值可能会低估持仓价值。但这仍是最客观的计价方式。在我看来，我们所有投资通常都被低估——否则我们不会持有。</p><h3 id="市场预测" tabindex="-1">市场预测 <a class="header-anchor" href="#市场预测" aria-label="Permalink to &quot;市场预测&quot;">​</a></h3><p>我们的第六条基本原则（来自11月文件）规定：<strong>我不从事预测股市或经济波动的业务。若你认为我有此能力，或认为这是投资计划的核心，你不应加入本合伙公司。</strong></p><p>当然，这条原则可能被指责模糊、复杂、模棱两可，但我相信绝大多数合伙人都能理解其核心。我们买卖股票，从不基于他人对股市的判断（我从不发表此类观点），而是基于我们对企业未来的判断。股市走势很大程度上决定<strong>我们何时能获利</strong>，而对企业的分析准确度，决定<strong>我们能否获利</strong>。简言之，我们专注于<strong>会发生什么</strong>，而非<strong>何时发生</strong>。</p><p>在百货行业，我可以笃定地说12月业绩会好于7月（可见我已快速掌握零售行业规律）。真正重要的是，今年12月业绩同比增幅能否超越竞争对手，以及我们如何为未来业绩铺路。但在投资领域，我既无法判断12月是否好于7月，甚至无法确定12月不会出现巨额亏损——这种情况时有发生。我们的投资组合，根本不在意地球绕太阳公转需要365.25天，更不在意你和美国国税局要求我按自然年汇报业绩。因此，我们必须用<strong>道指代表的市场整体表现</strong>作为衡量标准。</p><p>我们坚信，长期来看道指会有不错表现（即便圣诞节在7月也会如期到来），只要我们持续跑赢道指，最终收益必然可观。这就像零售商对标西尔斯的销售额与利润率——年年超越，终会脱颖而出。</p><p>我重提“市场预测”话题，是因为道指从2月高点995点跌至5月约865点后，几位合伙人致电建议，认为股市还会大幅下跌。这让我产生两个疑问：</p><ol><li><p>若他们2月就知道道指5月会跌到865点，为何当时不告诉我？</p></li><li><p>若2月时他们无法预测未来三个月走势，5月又凭什么确定？</p></li></ol><p>每当股市大跌百点左右，就会有人建议我们清仓观望，等未来局势明朗再入场。我再次重申两点：</p><ol><li><p>未来对我而言从未清晰过（若你能看清未来数月甚至数小时走势，请立刻致电我）；</p></li><li><p>股市大涨百点后，从没人来电提醒我局势不明，尽管回头看，2月的市场同样迷雾重重。</p></li></ol><p>若我们仅凭猜测或情绪，决定是否参与具备长期优势的生意，必将陷入困境。我们不会因为所谓“专家”预测股价还会下跌，就抛售定价合理的资产——即便这类预测偶尔会应验。同理，我们也不会因为“专家”预判股价上涨，就买入估值过高的证券。谁会因为他人对股市的猜测，买卖一家私营企业呢？股票的流动性本应是可利用的优势，当股价极端高估或低估时，我们可以顺势操作；绝不能让其变成劣势，被股价的短期波动左右判断。本杰明·格雷厄姆《聪明的投资者》第二章**“投资者与股市波动”**，完美阐述了这一理念。在我看来，这一章是投资领域最重要的文字。</p><p>11月左右，我会发送信件，告知1967年入伙意向及1966年税务情况预估。</p><p>此致</p><p>沃伦·巴菲特</p><hr>',45)])])}const g=d(e,[["render",o]]);export{c as __pageData,g as default};
